namespace Microsoft.Falcon.LibOnePortal.Utility
{
    using System.Runtime.InteropServices;
    using System.Security.Cryptography.X509Certificates;
    using System.Text.Json;
    using System.Text.Json.Serialization;
    using Microsoft.AspNetCore.Builder;
    using Microsoft.AspNetCore.Hosting;
    using Microsoft.Extensions.DependencyInjection;
    using Microsoft.Extensions.Hosting;
    using Microsoft.Falcon.AppSettings.V2;
    using Microsoft.Falcon.Loader;

    /// <summary>
    /// OnePortalServiceSPA for IHostApplicationBuilder, which is recommended to use in ASP.NET Core 8.0 and later for SPA.
    /// </summary>
    public abstract class OnePortalServiceSPA
    {
        private const string OnePortalConfigPath = "Config/1p.config.json";
        private readonly JsonSerializerOptions jsonOpts = new JsonSerializerOptions() { UnmappedMemberHandling = JsonUnmappedMemberHandling.Disallow };

        /// <summary>
        /// Initializes a new instance of the <see cref="OnePortalServiceSPA"/> class.
        /// </summary>
        public OnePortalServiceSPA()
        {
            if (File.Exists(OnePortalConfigPath))
            {
                this.OneportalConfig = JsonSerializer.Deserialize<OnePortalConfig>(File.ReadAllText(OnePortalConfigPath), options: this.jsonOpts) ?? new OnePortalConfig();
            }
            else
            {
                this.OneportalConfig = new OnePortalConfig();
            }
        }

        /// <summary>
        /// Gets service name.
        /// </summary>
        public abstract string Name { get; }

        /// <summary>
        /// Gets one portal config.
        /// </summary>
        public virtual OnePortalConfig OneportalConfig { get; private set; }

        /// <summary>
        /// Run Oneportal service.
        /// </summary>
        /// <typeparam name="T">Service implementation.</typeparam>
        /// <param name="args">cmd args from main.</param>
        /// <returns>async task.</returns>
        public static Task RunAsync<T>(string[] args)
            where T : OnePortalServiceSPA
        {
            var hostBuilder = WebApplication.CreateBuilder(args);
            var services = hostBuilder.Services;
            var onePortalServiceSPA = Activator.CreateInstance<T>();
            onePortalServiceSPA.ConfigureHostApplicationBuilder(hostBuilder);
            onePortalServiceSPA.ConfigureServices(services);
            var applicationBuilder = hostBuilder.Build();
            onePortalServiceSPA.ConfigureWebApplication(applicationBuilder);
            return applicationBuilder.RunAsync();
        }

        /// <summary>
        /// The Configuration method for HostApplicationBuilder.
        /// </summary>
        /// <param name="webApplicationBuilder">The host application builder.</param>
        public virtual void ConfigureHostApplicationBuilder(WebApplicationBuilder webApplicationBuilder)
        {
            // to do detect change to the certificatioon file and restart the service to load the new file
            var certPath = Environment.GetEnvironmentVariable("HTTPS_CERTIFICATE_FILE_PATH");

            webApplicationBuilder.WebHost.ConfigureKestrel(s =>
            {
                const int ONEPORTAL_HTTP_PORT = 5004;
                const int ONEPORTAL_HTTPS_PORT = 5005;
                s.ListenAnyIP(ONEPORTAL_HTTP_PORT, options =>
                {
                });

                s.ListenAnyIP(ONEPORTAL_HTTPS_PORT, options =>
                {
                    if (!string.IsNullOrEmpty(certPath))
                    {
                        var certificate = this.GetPemCertificate(certPath);
                        options.UseHttps(certificate);
                    }
                    else
                    {
                        options.UseHttps();
                    }
                });
            });
        }

        /// <summary>
        /// The Configuration method for WebApplication.
        /// </summary>
        /// <param name="webApp">webApp.</param>
        public virtual void ConfigureWebApplication(WebApplication webApp)
        {
            webApp.UseOnePortalSPA(this.OneportalConfig);
            webApp.MapControllers();
            webApp.MapFallbackToFile("/index.html");
        }

        /// <summary>
        /// The services configuration method.
        /// </summary>
        /// <param name="services">The services collection.</param>
        public virtual void ConfigureServices(IServiceCollection services)
        {
            services.AddOnePortalFalconServicesSPA(this.Name, this.OneportalConfig);
            this.InjectDependencies(services);
        }

        /// <summary>
        /// SetupDependencyInjection.
        /// </summary>
        /// <param name="services">services.</param>
        public abstract void InjectDependencies(IServiceCollection services);

        /// <summary>
        /// Get the certificate from .pem file.
        /// </summary>
        /// <param name="certPemFilePath">file path to the file.</param>
        /// <returns>certificate.</returns>
        private X509Certificate2 GetPemCertificate(string certPemFilePath)
        {
            if (string.IsNullOrWhiteSpace(certPemFilePath))
            {
                throw new ArgumentNullException();
            }

            var ext = Path.GetExtension(certPemFilePath);
            if (ext != ".pem")
            {
                throw new ArgumentException($"Invalid extension {ext} found in certificate file path {certPemFilePath}, .pem extension must be used");
            }

            var certificate = X509Certificate2.CreateFromPemFile(
            certPemFilePath);
            return RuntimeInformation.IsOSPlatform(OSPlatform.Windows) ? new X509Certificate2(certificate.Export(X509ContentType.Pkcs12)) : certificate;
        }
    }
}

