namespace Microsoft.Falcon.LibOnePortal.Utility
{
    using System.Reflection;

    /// <summary>
    /// oneportal config, maps to 'Config/1p.config.json'.
    /// </summary>
    public class OnePortalConfig
    {
        /// <summary>
        /// Gets or sets a value indicating whether to initialize as proxy service.
        /// </summary>
        public bool EnableProxy { get; set; } = false;

        /// <summary>
        /// Gets or sets destination url for proxy.
        /// </summary>
        public string ProxyDestUrl { get; set; } = string.Empty;

        /// <summary>
        /// Gets or sets a value indicating whether to skip ssl validation in proxy handling.
        /// </summary>
        public bool SkipProxySslValidation { get; set; } = false;

        /// <summary>
        /// Gets or sets azure app id used for bearer token authentication in backend.
        /// </summary>
        public string AADAuthAppId { get; set; } = Secret.Constants.EqAppId;

        /// <summary>
        /// Gets or sets a value indicating whether to enable API access using tokens issued from both PME and Msft tenants.
        /// NOTE: pre-requirements for enabling PME access:
        ///         1-Azure App Id specified via 'AADAuthAppId' config property is required to be multitenant (PME -> Msft)
        ///         2-Client must issue used token with scope 'api://app_id/.default'.
        /// </summary>
        public bool EnablePmeAndMsftApiAccess { get; set; } = false;

        /// <summary>
        /// Overrides parameter values from corresponding environment variables.
        /// ex: OnePortalConfig.EnableProxy=true.
        /// </summary>
        public void OverrideConfigFromEnvVars()
        {
            Type t = this.GetType();
            foreach (PropertyInfo info in t.GetProperties())
            {
                var envVarName = $"{t.Name}.{info.Name}";
                var envVarValue = Environment.GetEnvironmentVariable(envVarName);
                if (!string.IsNullOrEmpty(envVarValue) && info.CanWrite)
                {
                    if (info.PropertyType == typeof(string))
                    {
                        info.SetValue(this, envVarValue);
                    }
                    else if (info.PropertyType == typeof(bool))
                    {
                        info.SetValue(this, bool.Parse(envVarValue));
                    }
                    else
                    {
                        throw new NotSupportedException($"Unsupported type {info.PropertyType}");
                    }
                }
            }
        }
    }
}

