namespace LibOnePortal.Middleware
{
    using Microsoft.AspNetCore.Http;
    using Microsoft.Extensions.Logging;
    using Microsoft.Falcon.LibOnePortal.Utility;

    /// <summary>
    /// Middle ware to add trace id.
    /// </summary>
    public class OnePortalMiddleware
    {
        /// <summary>
        /// Next delegate.
        /// </summary>
        private readonly RequestDelegate next;

        /// <summary>
        /// logger.
        /// </summary>
        private ILogger<OnePortalMiddleware> logger;

        /// <summary>
        /// Initializes a new instance of the <see cref="OnePortalMiddleware"/> class.
        /// </summary>
        /// <param name="next">next delegate.</param>
        /// <param name="logger">logger.</param>
        public OnePortalMiddleware(RequestDelegate next, ILogger<OnePortalMiddleware> logger)
        {
            this.next = next;
            this.logger = logger;
        }

        /// <summary>
        /// Middle ware invoke aync.
        /// </summary>
        /// <param name="context">context.</param>
        /// <returns>Task for async.</returns>
        public async Task InvokeAsync(HttpContext context)
        {
            this.logger.LogInformationEx($"Request starts");

            // Add the trace ID to the response headers
            context.Response.OnStarting(() =>
            {
                const string PODEnvVariableName = "POD__ID";
                const string TraceIdentifierHeader = "TraceIdentifier";
                const string PODNameHeader = "PodName";

                context.Response.Headers[TraceIdentifierHeader] = context.TraceIdentifier;
                var podName = Environment.GetEnvironmentVariable(PODEnvVariableName);

                if (!string.IsNullOrEmpty(podName))
                {
                    context.Response.Headers[PODNameHeader] = podName;
                }

                return Task.CompletedTask;
            });

            context.Response.OnCompleted(() =>
            {
                this.logger.LogInformationEx($"Request ends");
                return Task.CompletedTask;
            });

            // Call the next middleware in the pipeline
            await this.next(context);
        }
    }
}

