namespace LibOnePortal.Utility
{
    using System;
    using System.Linq;
    using System.Net.Http;
    using System.Net.Http.Headers;
    using System.Net.WebSockets;
    using Microsoft.AspNetCore.Authentication;
    using Microsoft.AspNetCore.Http;
    using Microsoft.Extensions.Primitives;

    /// <summary>
    /// proxy handler.
    /// </summary>
    internal class ProxyHandler : IDisposable
    {
        private const string WebSocketProtoclHeaderKey = "Sec-WebSocket-Protocol";

        private const int WebSocketProxyBufferLen = 256;

        // TODO: debug problem caused by copying "Accept-Encoding"
        private readonly string[] proxyHeadersBlackList = { "Accept-Encoding", "Host" };

        /// <summary>
        /// The base target URI.
        /// </summary>
        private readonly Uri baseDestUrl;

        /// <summary>
        /// http client.
        /// </summary>
        private HttpClient httpClient;

        /// <summary>
        /// Initializes a new instance of the <see cref="ProxyHandler"/> class.
        /// </summary>
        /// <param name="destUrl">dest url.</param>
        /// <param name="skipProxySslValidation">slip ssl validation.</param>
        public ProxyHandler(string destUrl, bool skipProxySslValidation)
        {
            this.baseDestUrl = new Uri(destUrl);
            var handler = new HttpClientHandler();
            if (skipProxySslValidation)
            {
                handler.ClientCertificateOptions = ClientCertificateOption.Manual;
                handler.ServerCertificateCustomValidationCallback =
                    (httpRequestMessage, cert, cetChain, policyErrors) =>
                    {
                        return this.baseDestUrl.Host.Equals(httpRequestMessage?.RequestUri?.Host, StringComparison.OrdinalIgnoreCase);
                    };
            }

            this.httpClient = new HttpClient(handler);
        }

        /// <summary>
        /// handle.
        /// </summary>
        /// <param name="ctx">http context.</param>
        /// <returns>none.</returns>
        public async Task Handle(HttpContext ctx)
        {
            if (ctx.WebSockets.IsWebSocketRequest)
            {
                await this.HandleWebSocket(ctx);
            }
            else
            {
                var authToken = await ctx.GetTokenAsync("id_token");
                var proxyReq = this.CloneHttpRequest(ctx.Request, this.baseDestUrl, authToken);

                var origResp = await this.httpClient.SendAsync(proxyReq);
                await this.CloneHttpResponse(ctx.Response, origResp);
                await ctx.Response.CompleteAsync();
